class Solution:
    def reorderedPowerOf2(self, n: int) -> bool:
        def get_digits(num):
            return sorted(str(num))

        for i in range(31):
            power_of_two = 2 ** i
            if get_digits(power_of_two) == get_digits(n):
                return True
        return False
